import { describe, expect, it } from 'vitest';
import { DEFAULT_MFSK, demodulateFrame, modulateFrame, type MfskOptions } from './mfsk-modem';
import { resolveFecProfile } from './fec-codec';
import { applyMarsChannel } from './mars-channel';
import { signalAmplitudeForEbN0 } from './link-budget';
import { buildWhipReplicasIq, foldWhipReplicas } from './whip-diversity';

const KEY = Uint8Array.from(
  'GNOSIS-RFKEY/1 prefixHash=66 prefixLen=7 boundaryDimension=12 stationCount=2 crc16=a4ce',
  (c) => c.charCodeAt(0),
);
const SPS = 300; // 2.4 MS/s / 8000 baud

function opts(fecName: string, amplitude: number): MfskOptions {
  return { ...DEFAULT_MFSK, fec: resolveFecProfile(fecName), amplitude };
}

describe('mfsk-modem', () => {
  it('clean round-trip recovers the exact cache key', () => {
    const o = opts('rs+conv', 0.6);
    const iq = modulateFrame(KEY, o);
    const res = demodulateFrame(iq, o);
    expect(res.ok).toBe(true);
    expect(res.payload).toEqual(KEY);
  });

  it('Mars-channel A/B: FEC recovers what raw cannot, at the same Eb/N0', () => {
    const ebN0 = 5; // the FEC cliff: raw 0/N, rs+conv N/N
    const amp = signalAmplitudeForEbN0(ebN0, 'mfsk8', SPS);
    const SEEDS = [11, 22, 33, 44, 55];

    let fecOk = 0;
    let rawOk = 0;
    for (const seed of SEEDS) {
      const fecIq = applyMarsChannel(modulateFrame(KEY, opts('rs+conv', amp)), {
        noiseRms: 0.25,
        seed,
      }).iq;
      const fecRes = demodulateFrame(fecIq, opts('rs+conv', amp), 0, 8 * SPS);
      if (fecRes.ok && fecRes.payload && Buffer.from(fecRes.payload).equals(Buffer.from(KEY))) {
        fecOk++;
      }
      const rawIq = applyMarsChannel(modulateFrame(KEY, opts('none', amp)), {
        noiseRms: 0.25,
        seed,
      }).iq;
      const rawRes = demodulateFrame(rawIq, opts('none', amp), 0, 8 * SPS);
      if (rawRes.ok && rawRes.payload && Buffer.from(rawRes.payload).equals(Buffer.from(KEY))) {
        rawOk++;
      }
    }
    // FEC closes the gap on every seed; raw is destroyed at this Eb/N0.
    expect(fecOk).toBe(SEEDS.length);
    expect(rawOk).toBe(0);
  });

  it('Whip fork/race/fold survives a dead replica (the fade)', () => {
    const ebN0 = 10;
    const amp = signalAmplitudeForEbN0(ebN0, 'mfsk8', SPS);
    const o = opts('rs+conv', amp);
    const replicas = 3;
    const built = buildWhipReplicasIq(KEY, o, replicas);
    const chan = applyMarsChannel(built.iq, { noiseRms: 0.25, seed: 7 }).iq;
    // deep fade: zero the entire first replica window (DC)
    const stride = built.frameSamples + built.gapSamples;
    for (let p = 0; p < stride * 2 && p < chan.length; p++) chan[p] = 128;
    const fold = foldWhipReplicas(chan, o, replicas, KEY.length, built.gapSamples);
    expect(fold.ok).toBe(true);
    expect(fold.winnerReplica).toBeGreaterThanOrEqual(1);
    expect(fold.payload && Buffer.from(fold.payload).equals(Buffer.from(KEY))).toBe(true);
  });
});
